INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '125207bc-1a41-4dda-ad7d-e4341aaaf433',
  '00000000-0000-0000-0000-000000000001',
  $escape$Fiber Routing — Parameters, Groups, and Prefixes Done Right$escape$,
  $escape$Fiber's router is built on fasthttp and uses a radix tree, making it one of the fastest in the Go ecosystem. Define routes directly on the app instance or scope them with `app.Group()` to share a prefix and middleware stack.

Route parameters use the `:param` syntax — access them via `c.Params("param")`. For optional segments, append `?`; for wildcards, use `*`. Fiber resolves conflicts deterministically: static segments beat parameterized ones, so `/users/me` always wins over `/users/:id`.

Grouping is where Fiber shines for API versioning. `app.Group("/api/v1")` returns a `fiber.Router` — mount middleware on the group and it applies only to those routes. Nest groups freely: a `/api` group can contain a `/users` subgroup with its own auth middleware. This keeps route registration declarative and co-located with the feature, not scattered across a monolithic route file. Use `app.Use()` on a group for prefix-scoped middleware without affecting global handlers.$escape$,
  $escape$package main

import "github.com/gofiber/fiber/v2"

func main() {
    app := fiber.New()

    api := app.Group("/api")
    v1 := api.Group("/v1", authMiddleware) // prefix + middleware

    users := v1.Group("/users")
    users.Get("/", listUsers)           // GET /api/v1/users
    users.Get("/:id", getUser)          // GET /api/v1/users/:id
    users.Get("/me", getMe)             // static wins over :id
    users.Post("/", createUser)         // POST /api/v1/users

    app.Listen(":3000")
}$escape$,
