INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '00f7f1b1-ddc4-48d1-9bc3-ced892b26a55',
  '00000000-0000-0000-0000-000000000001',
  $escape$Fiber Middleware — Request Pipeline, Global vs Route-Specific, and Why Order Is Everything$escape$,
  $escape$Fiber's middleware stack is a chain of `Handler` functions executed in registration order. Global middleware is registered with `app.Use()` before any route definitions — it intercepts every request. Route-specific middleware is passed as variadic arguments before the final handler, scoping it to that route only.

Order is deterministic and critical. If you register a rate limiter after your logger, the logger still runs on throttled requests. If you call `c.Next()` inside a middleware, execution passes to the next handler in the chain; omitting it short-circuits the pipeline entirely — useful for auth guards, harmful if accidental.

Fiber groups (`app.Group()`) let you apply middleware to a subtree of routes without polluting the global chain. A `/api/v1` group with JWT validation keeps public routes untouched. Middleware registered on a group runs before any group-level route handler, but after any global middleware already registered above it. Stack your high-frequency, low-cost middleware (logging, request ID) first; expensive middleware (auth, body parsing) only where needed.$escape$,
  $escape$package main

import (
	"github.com/gofiber/fiber/v2"
	"github.com/gofiber/fiber/v2/middleware/logger"
	"github.com/gofiber/fiber/v2/middleware/limiter"
)

func JWTGuard(c *fiber.Ctx) error {
	token := c.Get("Authorization")
	if token == "" {
		return c.SendStatus(fiber.StatusUnauthorized)
	}
	return c.Next()
}

func main() {
	app := fiber.New()

	// Global: runs on every request
	app.Use(logger.New())

	// Public route — no auth middleware
	app.Get("/health", func(c *fiber.Ctx) error {
		return c.SendString("ok")
	})

	// Protected group — JWTGuard + rate limiter scoped here only
	api := app.Group("/api", JWTGuard, limiter.New())
	api.Get("/bytes", func(c *fiber.Ctx) error {
		return c.JSON(fiber.Map{"data": "bytes"})
	})

	app.Listen(":3000")
}$escape$,
  $escape$go$escape$,
