INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '20ed34ea-a436-4d93-9d90-32207371f9b0',
  '00000000-0000-0000-0000-000000000001',
  $escape$Fiber + GORM — Killing N+1 Queries and Managing Migrations the Right Way$escape$,
  $escape$Fiber has no built-in ORM — you wire one in yourself. GORM is the dominant choice, but its convenience hides a classic trap: N+1 queries. When you call `db.Find(&posts)` then loop to fetch each post's author, GORM fires one query per row. In a Fiber handler returning 100 posts, that's 101 database round-trips.

Fix it with `Preload`: `db.Preload("Author").Find(&posts)` — GORM issues two queries total, joining results in Go memory. For join-heavy reads, `db.Joins("Author").Find(&posts)` pushes the join to PostgreSQL instead.

For query builders vs full ORMs: GORM wins for CRUD-heavy APIs wired into Fiber; `sqlc` (code-gen from raw SQL) wins when query control matters — no reflection overhead, compile-time safety, idiomatic Go structs returned directly into `c.JSON()`.

Never use `AutoMigrate` in production. Pair Fiber apps with `golang-migrate` or `goose` — version-controlled, reversible SQL files that run as part of your container startup or CI pipeline, not ad-hoc schema diffs.$escape$,
  $escape$// Fiber handler — N+1 fixed with GORM Preload
app.Get("/posts", func(c *fiber.Ctx) error {
	var posts []Post

	// BAD — 1 + N queries
	// db.Find(&posts)

	// GOOD — 2 queries, joined in memory
	result := db.Preload("Author").Preload("Tags").Find(&posts)
	if result.Error != nil {
		return fiber.ErrInternalServerError
	}
	return c.JSON(posts)
})$escape$,
  $escape$go$escape$,
