INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '52bd3a37-9fae-4a37-9870-79eb7bc48674',
  '00000000-0000-0000-0000-000000000001',
  $escape$Fiber Security Stack — CORS, Rate Limiting, and Headers in One Setup$escape$,
  $escape$Fiber's middleware ecosystem lets you lock down an API in minutes. Use `limiter.New` from `github.com/gofiber/contrib/limiter` to throttle requests per IP — set `Max` and `Expiration` to control burst windows. For CORS, `cors.New` accepts an `AllowOrigins` slice and supports per-route mounting, so public endpoints and authenticated ones carry different policies. Security headers come via `helmet.New()`, which sets `X-Content-Type-Options`, `X-Frame-Options`, `Strict-Transport-Security`, and CSP in one call — no manual `c.Set` chains needed. Against injection, avoid `c.QueryParser` into raw SQL; always use parameterized queries via `pgx`. Fiber's `BodyLimit` middleware caps payload size, preventing large-body DoS. Stack order matters: place `limiter` before `cors` and `helmet` before your route handlers so every response — including errors — carries the right headers. Chain them globally on `app.Use` unless a route genuinely needs different behavior.$escape$,
  $escape$app := fiber.New(fiber.Config{BodyLimit: 1 * 1024 * 1024})

app.Use(limiter.New(limiter.Config{
	Max:        60,
	Expiration: 1 * time.Minute,
}))

app.Use(helmet.New())

app.Use(cors.New(cors.Config{
	AllowOrigins: "https://app.example.com",
	AllowMethods: "GET,POST,PUT,DELETE",
	AllowHeaders: "Authorization,Content-Type",
}))

app.Get("/health", func(c *fiber.Ctx) error {
	return c.SendStatus(fiber.StatusOK)
})$escape$,
  $escape$go$escape$,
