INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'fed5aa82-4d20-4831-851d-57467230cb56',
  '00000000-0000-0000-0000-000000000001',
  $escape$Fiber — REST Versioning, Route Groups, and OpenAPI Without the Boilerplate$escape$,
  $escape$Fiber's `app.Group()` is the right primitive for API versioning — prefix once, inherit everywhere. Mount `/api/v1` and `/api/v2` as sibling groups so breaking changes land in v2 while v1 stays stable. Attach a deprecation middleware directly to the v1 group: set a `Deprecation: true` response header on every v1 response without touching individual handlers.

For OpenAPI, use `swag init` with `github.com/gofiber/contrib/swagger`. Annotate handlers with `// @Router /api/v2/users/{id} [get]`, `// @Param`, and `// @Success` comments, then mount `swagger.HandlerDefault` at `/swagger/*`. Fiber serves the Swagger UI with no custom HTML.

REST conventions that matter in Fiber: use `c.Status(fiber.StatusCreated).JSON(body)` on POST — never bare `c.JSON()`. Use `c.QueryInt("page", 1)` for pagination with a safe default. Return errors through a shared struct so clients get a consistent shape. Use `c.Locals()` to pass decoded JWT claims from auth middleware into handlers — avoid re-parsing the token per route.$escape$,
  $escape$func main() {
	app := fiber.New()

	api := app.Group("/api")

	v1 := api.Group("/v1", func(c *fiber.Ctx) error {
		c.Set("Deprecation", "true")
		return c.Next()
	})
	v1.Get("/users/:id", getUser)

	v2 := api.Group("/v2")
	v2.Get("/users/:id", getUserV2)
	v2.Post("/users", func(c *fiber.Ctx) error {
		return c.Status(fiber.StatusCreated).JSON(fiber.Map{"id": "abc"})
	})

	app.Get("/swagger/*", swagger.HandlerDefault)
	app.Listen(":3000")
}$escape$,
