INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'ac264c0e-3007-431c-bd94-e9b4bd1f64f0',
  '00000000-0000-0000-0000-000000000001',
  $escape$Fiber Logging — Structured Logs, Correlation IDs, and Request Middleware$escape$,
  $escape$Fiber's `requestid` and `logger` middlewares combine to give you structured, traceable request logs with minimal setup. Register `requestid.New()` first — it injects a UUID into `c.Locals("requestid")`, accessible via `${locals:requestid}` inside the logger's format string.

The `logger.New()` middleware accepts a `Config.Format` string supporting built-in tokens: `${status}`, `${latency}`, `${method}`, `${path}`, `${ip}`, and any custom local via `${locals:key}`. Wrap those tokens in a JSON template to emit newline-delimited JSON access logs — no external library required.

For deeper integration, set `Config.Output` to any `io.Writer` — point it at a `zerolog.Writer` to merge access logs into your application's structured log stream.

Inside handlers, extract the correlation ID with `c.Locals("requestid").(string)` and thread it into downstream service calls or outgoing HTTP headers (`X-Request-ID`). Propagating the same ID across services lets you reconstruct distributed traces from logs alone — no dedicated tracing backend needed for simpler deployments.$escape$,
  $escape$app := fiber.New()

app.Use(requestid.New())
app.Use(logger.New(logger.Config{
    Format: `{"time":"${time}","status":${status},"latency":"${latency}","method":"${method}","path":"${path}","request_id":"${locals:requestid}"}` + "\n",
}))

app.Get("/health", func(c *fiber.Ctx) error {
    rid := c.Locals("requestid").(string)
    c.Set("X-Request-ID", rid)
    return c.JSON(fiber.Map{"status": "ok", "request_id": rid})
})$escape$,
  $escape$go$escape$,
