INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '51acc528-dc85-4152-8f1f-c830a2ad8c08',
  '00000000-0000-0000-0000-000000000001',
  $escape$Fiber Background Jobs — Goroutines, Cron, and Graceful Shutdown$escape$,
  $escape$Fiber has no built-in job scheduler, so the idiomatic pattern is launching goroutines before `app.Listen()` and wiring their lifecycle into Fiber's `app.Hooks().OnShutdown()`. For scheduled work, pair Fiber with `robfig/cron`: instantiate the scheduler, register jobs, call `c.Start()`, then stop it cleanly on shutdown. For task queues, use a buffered channel as the queue and fan out to a worker pool of goroutines that drain it. Each worker receives a `context.Context` derived from a root context cancelled on shutdown — this propagates termination without leaking goroutines. Avoid spawning raw goroutines inside route handlers; instead, push work onto the channel and return immediately, keeping handler latency low. For one-off deferred tasks (e.g. post-request email), `app.Hooks().OnShutdown()` lets you drain the queue before the process exits, preventing silent job loss. Use `app.ShutdownWithTimeout(10 * time.Second)` to bound the drain window.$escape$,
  $escape$package main

import (
	"github.com/gofiber/fiber/v2"
	"github.com/robfig/cron/v3"
)

func main() {
	app := fiber.New()
	queue := make(chan string, 100)

	c := cron.New()
	c.AddFunc("@every 1m", func() { queue <- "scheduled-task" })
	c.Start()

	go func() {
		for job := range queue {
			processJob(job)
		}
	}()

	app.Hooks().OnShutdown(func() error {
		c.Stop()
		close(queue)
		return nil
	})

	app.Listen(":3000")
}$escape$,
  $escape$go$escape$,
